/*
* Returns a String for the header subscreen to display the title of the page
*
* by Mateo Rada Arias
*/

return "Cargo Quotation Process";

/*
* This function calculates de Underwriting year based on the date selected on the Inception Date field,
* it sets the threshold (from July to June) based on the selected date and compares the date to the threshold,
* if it falls in the threshold returns the current year, otherwise it returns the previous year
*
* by Mateo Rada Arias
*/
const inceptionDateStr = this.CQP_INCEPTION_DATE; // Get data from Inception Date dropwdown as a string

// Check if the date hasn't been selected yet
if(inceptionDateStr == null){
    return "";
}

let inceptionDate = new Date(inceptionDateStr); // Create a Date object with the date string
const currentYear = inceptionDate.getFullYear(); // Get current date's year

// Define July 1st of the current year and June 30th of the next year
const julyStart = new Date(currentYear, 6, 1); // Month is 0-indexed: 6 = July
const juneEnd = new Date(currentYear + 1, 5, 30); // 5 = June

// Check if inception date is between July of current year and June of next year
if (inceptionDate >= julyStart && inceptionDate <= juneEnd) {
    return currentYear;
} else {
    return currentYear - 1;
}

let actions = this.CQP_ACTION
let CQP_UPDATE_NAME = this.CQP_UPDATE_NAME
let CQP_INSURED_NAME_NEW = this.CQP_INSURED_NAME_NEW

try {
    if (actions == "NEW") {
        if (this.CQP_CREATE_NEW_INSURED_NAME == "NO") {
            if (CQP_UPDATE_NAME == "YES") {
                return CQP_INSURED_NAME_NEW
            } else {
                return this.CQP_INSURED_NEW_CREATED.CQP_INSURED_NAME
            }
        } else {
            return CQP_INSURED_NAME_NEW
        }
    } else if (actions == "RENEWAL") {
        if (CQP_UPDATE_NAME == "YES") {
            return CQP_INSURED_NAME_NEW
        } else {
            return this.CQP_INSURED_RENEWAL.CQP_INSURED_NAME
        }
    } else if (actions == "CLONE") {
        return this.CQP_INSURED_CLONE.CQP_INSURED_NAME
    }
} catch (error) {
    return ""
}

return ""

/*
* by Diego Tapia
*/

if (this.CQP_SEARCH_CODE != null && this.CQP_SEARCH_CODE != undefined && this.CQP_SEARCH_CODE != "" && window.originalValue == undefined) {
    window.originalValue = this.CQP_BROKER_STATUS
}

if (window.originalValue == undefined) {
    if (this.CQP_QUOTE == "NO") {
        return "CLOSE"
    } else {
        return "OPEN"
    }
} else {
    if (this.CQP_QUOTE == "NO") {
        return "CLOSE"
    } else {
        return window.originalValue
    }
}

let actions = this.CQP_ACTION
try {
    if (actions == "NEW") {
        if (this.CQP_CREATE_NEW_INSURED_NAME == "NO") {
            return this.CQP_INSURED_NEW_CREATED.CQP_INSURED_CODE
        } else {
            return Array.from({length: 10}, () => Math.floor(Math.random() * 10)).join('')
        }
    } else if (actions == "RENEWAL") {
        return this.CQP_INSURED_RENEWAL.CQP_INSURED_CODE
    } else if (actions == "CLONE") {
        return this.CQP_INSURED_CLONE.CQP_INSURED_CODE
    }
} catch (error) {
    return ""
}

return ""

/*
* Calc Show request error dialog
* by Helen Callisaya
* Modified by Mateo Rada
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERROR.data.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == null || 
    this.FORTE_ERROR.data.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}
